template <typename K = ull, typename V = int, int SIZE = 1 << 20, bool MIX_KEYS = true>
class FastHashMap {
	/**
	* 【开放寻址哈希表使用事项】
	* 不支持删除/修改单个 key，不如自带的哈希表灵活
	* 255 次溢出 clear 触发一次 memset，使用了 gen+tag 进行优化，避免每个单例都 memset
	* 表满了会卡住，建议 key 的数量远小于 SIZE
	* 注意 key 本身是否为分布均匀的哈希值，若是则 MIX_KEYS 设为 false（如字符串哈希、双哈希拼成的 ull、坐标编码后哈希等），否则启用 mix
	* K 的类型只能是小于 8 字节的，所以能用的为 int ll ull pii
	* V 的类型随意
	*/

	static_assert((SIZE& (SIZE - 1)) == 0, "SIZE 必须是 2 的幂次");

	K keys[SIZE];
	V values[SIZE];
	uint8_t gen[SIZE]{};
	uint8_t tag = 1;

	static ull mix(ull x) {
		x ^= x >> 30;
		x *= 0xbf58476d1ce4e5b9ULL;
		x ^= x >> 27;
		x *= 0x94d049bb133111ebULL;
		x ^= x >> 31;
		return x;
	}

	int hash(K key) {
		ull x = 0;
		if constexpr (is_same_v<K, ull>)x = key; // 本来就是 ull，直接赋值
		else if constexpr (is_same_v<K, ll>)x = static_cast<ull>(key); // ll 也能直接转，跳过 memcpy
		else memcpy(&x, &key, sizeof(K)); // 其他类型才 memcpy

		if constexpr (MIX_KEYS) x = mix(x);
		return x & (SIZE - 1);
	}

public:
	void clear() {
		// gen + tag 实现更快的清空
		if (++tag == 0) { // 溢出, 256 次 clear 才触发一次
			memset(gen, 0, sizeof(gen));
			tag = 1;
		}
	}

	void insert(K key, V val) {
		int h = hash(key);
		while (gen[h] == tag && keys[h] != key)
			h = (h + 1) & (SIZE - 1);
		gen[h] = tag;
		keys[h] = key;
		values[h] = val;
	}

	V get(K key) {
		int h = hash(key);
		while (gen[h] == tag) {
			if (keys[h] == key) return values[h];
			h = (h + 1) & (SIZE - 1);
		}
		return {}; // 没查到
	}
};
